  _g(a) { const i = a >>> PS; let p = this.p[i]; if (!p) { p = new Uint8Array(PZ); this.p[i] = p; } return p; }
  r8(a) { a >>>= 0; return (this.p[a >>> PS] || 0)[a & PM]; }
  w8(a, v) { a >>>= 0; this._g(a)[a & PM] = v; }
  r32(a) {
    a >>>= 0; const o = a & PM, p = this.p[a >>> PS];
    if (!p) return 0;
    if (o < PZ - 3) return (p[o] | (p[o+1] << 8) | (p[o+2] << 16) | (p[o+3] << 24)) >>> 0;
    return (this.r8(a) | (this.r8(a+1) << 8) | (this.r8(a+2) << 16) | (this.r8(a+3) << 24)) >>> 0;
  }
  w32(a, v) {
    a >>>= 0; const o = a & PM, p = this._g(a);
    if (o < PZ - 3) { p[o]=v; p[o+1]=v>>>8; p[o+2]=v>>>16; p[o+3]=v>>>24; return; }
    this.w8(a,v); this.w8(a+1,v>>>8); this.w8(a+2,v>>>16); this.w8(a+3,v>>>24);
  }
  r16(a) { return this.r8(a) | (this.r8(a+1) << 8); }
  w16(a, v) { this.w8(a, v); this.w8(a+1, v>>>8); }
  str(a) {
    a >>>= 0; const b = [];
    while (1) { const c = this.r8(a++); if (!c) break; b.push(c); if (b.length > 4096) break; }
    return String.fromCharCode(...b);
  }
  loadSeg(va, data, off, fsz) {
    for (let i = 0; i < fsz; i++) this.w8(va + i, data[off + i]);
  }
  // Bulk write from buffer at addr (faster than byte-by-byte for reads)
  writeBulk(a, buf, n) {
    for (let i = 0; i < n; i++) {
      const ai = (a + i) >>> 0;
      this._g(ai)[ai & PM] = buf[i];
    }
  }
  // Bulk read to buffer
  readBulk(a, buf, n) {
    for (let i = 0; i < n; i++) buf[i] = this.r8((a + i) >>> 0);
  }
}

// Syscall numbers (x86_64 Linux)
const S_read=0,S_write=1,S_open=2,S_close=3,S_lseek=8,S_brk=12;
const S_exit=60,S_fsync=74,S_rename=82,S_mkdir=83,S_unlink=87,S_time=201;

function xlatFlags(f) {
  const ac = f & 7;
  let s = ac === 0 ? 'r' : ac === 1 ? 'w' : 'r+';
  if (f & 64 && s === 'r') s = 'r+';
  if (f & 512) s = s.includes('+') ? 'w+' : 'w';
  if (f & 1024) s = s.includes('+') ? 'a+' : 'a';
  return s;
}

// CPU
class CPU {
  constructor(mem, entry) {
    this.mem = mem;
    this.pc = entry >>> 0;
    this.npc = (entry + 4) >>> 0;
    this.r = new Int32Array(32);
    this.u = new Uint32Array(this.r.buffer);
    this.hi = 0; this.lo = 0;
    this.exitCode = null;
    this.ic = 0;
    this.heapEnd = 0;
    this.fds = new Map();
    this.nfd = 3;
    this.fds.set(0, {t:'s'}); this.fds.set(1, {t:'s'}); this.fds.set(2, {t:'s'});
  }

  run() {
    const m = this.mem, u = this.u, r = this.r;
    let pc = this.pc, npc = this.npc;
    let ic = 0;
    const checkExit = () => { this.exitCode !== null };

    while (this.exitCode === null) {
      const I = m.r32(pc);
      pc = npc;
      npc = (npc + 4) >>> 0;
      ic++;

      const op = I >>> 26;
      const rs = (I >>> 21) & 31, rt = (I >>> 16) & 31, rd = (I >>> 11) & 31;
      const sh = (I >>> 6) & 31;
      const si = (I << 16) >> 16;
      const ui = I & 0xFFFF;

      if (op === 0) {
        // SPECIAL
        const fn = I & 63;
        switch (fn) {
          case 0: u[rd] = (u[rt] << sh) >>> 0; break; // sll
          case 2: u[rd] = u[rt] >>> sh; break; // srl
          case 3: u[rd] = r[rt] >> sh; break; // sra
          case 4: u[rd] = (u[rt] << (u[rs] & 31)) >>> 0; break; // sllv
          case 6: u[rd] = u[rt] >>> (u[rs] & 31); break; // srlv
          case 7: u[rd] = r[rt] >> (u[rs] & 31); break; // srav
          case 8: npc = u[rs]; break; // jr
          case 9: { const t = u[rs]; u[rd||31] = (pc + 4) >>> 0; npc = t; break; } // jalr
          case 10: if (u[rt]===0) u[rd]=u[rs]; break; // movz
          case 11: if (u[rt]!==0) u[rd]=u[rs]; break; // movn
          case 12: { // syscall
            this.doSyscall(u, m, pc);
            if (this.exitCode !== null) break;
            break;
          }
          case 15: break; // sync
          case 16: u[rd] = this.hi >>> 0; break; // mfhi
          case 17: this.hi = u[rs]; break; // mthi
          case 18: u[rd] = this.lo >>> 0; break; // mflo
          case 19: this.lo = u[rs]; break; // mtlo
          case 24: { // mult (signed)
            const res = BigInt(r[rs]) * BigInt(r[rt]);
            this.lo = Number(res & 0xFFFFFFFFn) >>> 0;
            this.hi = Number((res >> 32n) & 0xFFFFFFFFn) >>> 0;
            break;
          }
          case 25: { // multu (unsigned)
            const res = BigInt(u[rs]) * BigInt(u[rt]);
            this.lo = Number(res & 0xFFFFFFFFn) >>> 0;
            this.hi = Number((res >> 32n) & 0xFFFFFFFFn) >>> 0;
            break;
          }
          case 26: { // div
            const a=r[rs], b=r[rt]; if(b){this.lo=(Math.trunc(a/b))>>>0;this.hi=(a%b)>>>0;} break;
          }
          case 27: { // divu
            const a=u[rs], b=u[rt]; if(b){this.lo=(a/b)>>>0;this.hi=(a%b)>>>0;} break;
          }
          case 32: case 33: u[rd]=(u[rs]+u[rt])>>>0; break; // add/addu
          case 34: case 35: u[rd]=(u[rs]-u[rt])>>>0; break; // sub/subu
          case 36: u[rd]=u[rs]&u[rt]; break; // and
          case 37: u[rd]=u[rs]|u[rt]; break; // or
          case 38: u[rd]=u[rs]^u[rt]; break; // xor
          case 39: u[rd]=~(u[rs]|u[rt])>>>0; break; // nor
          case 42: u[rd]=r[rs]<r[rt]?1:0; break; // slt
          case 43: u[rd]=(u[rs]>>>0)<(u[rt]>>>0)?1:0; break; // sltu
          case 48: case 50: case 52: case 54: break; // traps
          default: this.err(`SPECIAL fn=0x${fn.toString(16)} PC=0x${pc.toString(16)}`);
        }
      } else {
        switch (op) {
          case 2: npc=((pc+4)&0xF0000000)|((I&0x3FFFFFF)<<2); break; // j
          case 3: u[31]=(pc+4)>>>0; npc=((pc+4)&0xF0000000)|((I&0x3FFFFFF)<<2); break; // jal
          case 4: if(u[rs]===u[rt]) npc=(pc+4+(si<<2))>>>0; break; // beq
          case 5: if(u[rs]!==u[rt]) npc=(pc+4+(si<<2))>>>0; break; // bne
          case 6: if(r[rs]<=0) npc=(pc+4+(si<<2))>>>0; break; // blez
          case 7: if(r[rs]>0) npc=(pc+4+(si<<2))>>>0; break; // bgtz
          case 8: case 9: u[rt]=(u[rs]+si)>>>0; break; // addi/addiu
          case 10: u[rt]=r[rs]<si?1:0; break; // slti
          case 11: u[rt]=(u[rs]>>>0)<(si>>>0)?1:0; break; // sltiu
          case 12: u[rt]=u[rs]&ui; break; // andi
          case 13: u[rt]=u[rs]|ui; break; // ori
          case 14: u[rt]=u[rs]^ui; break; // xori
          case 15: u[rt]=(ui<<16)>>>0; break; // lui
          case 1: { // regimm
            const sub=rt, tgt=(pc+4+(si<<2))>>>0;
            if(sub===0){if(r[rs]<0)npc=tgt;} // bltz
            else if(sub===1){if(r[rs]>=0)npc=tgt;} // bgez
            else if(sub===16){u[31]=(pc+4)>>>0;if(r[rs]<0)npc=tgt;} // bltzal
            else if(sub===17){u[31]=(pc+4)>>>0;if(r[rs]>=0)npc=tgt;} // bgezal
            else this.err(`REGIMM ${sub}`);
            break;
          }
          case 16: case 17: case 18: case 19: case 20: case 21: case 22: case 23: break; // COPn
          case 28: { // SPECIAL2
            const fn2=I&63;
            switch(fn2){
              case 2: u[rd]=Math.imul(u[rs],u[rt])>>>0; break; // mul
              case 0: { // madd
                const res=BigInt(r[rs])*BigInt(r[rt]);
                let acc=(BigInt(this.hi>>>0)<<32n)|BigInt(this.lo>>>0);
                acc=(acc+res)&0xFFFFFFFFFFFFFFFFn;
                this.lo=Number(acc&0xFFFFFFFFn)>>>0;
                this.hi=Number(acc>>32n)>>>0;
                break;
              }
              case 1: { // maddu
                const res=BigInt(u[rs])*BigInt(u[rt]);
                let acc=(BigInt(this.hi>>>0)<<32n)|BigInt(this.lo>>>0);
                acc=(acc+res)&0xFFFFFFFFFFFFFFFFn;
                this.lo=Number(acc&0xFFFFFFFFn)>>>0;
                this.hi=Number(acc>>32n)>>>0;
                break;
              }
              case 32: u[rd]=u[rs]===0?32:Math.clz32(u[rs]); break; // clz
              case 33: u[rd]=~u[rs]===0?32:Math.clz32(~u[rs]>>>0); break; // clo
              default: this.err(`SPEC2 fn=0x${fn2.toString(16)}`);
            }
            break;
          }
          case 31: { // SPECIAL3
            const fn3=I&63;
            switch(fn3){
              case 0: u[rt]=(u[rs]>>>sh)&((1<<(rd+1))-1); break; // ext
              case 4: { const m2=((1<<(rd+1-sh))-1)<<sh; u[rt]=(u[rt]&~m2|((u[rs]<<sh)&m2))>>>0; break; } // ins
              case 32: {
                const sub=sh;
                switch(sub){
                  case 0: { // bitswap
                    let v=u[rt],r2=0;
                    for(let i=0;i<4;i++){let b=(v>>>(i*8))&0xff;b=((b&1)<<7)|((b&2)<<5)|((b&4)<<3)|((b&8)<<1)|((b&16)>>1)|((b&32)>>3)|((b&64)>>5)|((b&128)>>7);r2|=(b<<(i*8));}
                    u[rd]=r2>>>0; break;
                  }
                  case 2: u[rd]=(((u[rt]&0x00FF00FF)<<8)|((u[rt]&0xFF00FF00)>>>8))>>>0; break; // wsbh
                  case 16: u[rd]=((u[rt]&0xFF)<<24)>>24; break; // seb
                  case 24: u[rd]=((u[rt]&0xFFFF)<<16)>>16; break; // seh
                  default: this.err(`BSHFL 0x${sub.toString(16)}`);
                }
                break;
              }
              case 59: u[rt]=0; break; // rdhwr
              default: this.err(`SPEC3 fn=0x${fn3.toString(16)}`);
            }
            break;
          }
          // Loads
          case 32: u[rt]=((m.r8((u[rs]+si)>>>0))<<24)>>24; break; // lb
          case 33: u[rt]=((m.r16((u[rs]+si)>>>0))<<16)>>16; break; // lh
          case 34: { // lwl
            const a=(u[rs]+si)>>>0, al=a&~3, bo=a&3, mv=m.r32(al);
            if(bo===0)u[rt]=mv;else if(bo===1)u[rt]=(u[rt]&0xFF000000|mv>>>8)>>>0;
            else if(bo===2)u[rt]=(u[rt]&0xFFFF0000|mv>>>16)>>>0;
            else u[rt]=(u[rt]&0xFFFFFF00|mv>>>24)>>>0;
            break;
          }
          case 35: u[rt]=m.r32((u[rs]+si)>>>0); break; // lw
          case 36: u[rt]=m.r8((u[rs]+si)>>>0); break; // lbu
          case 37: u[rt]=m.r16((u[rs]+si)>>>0); break; // lhu
          case 38: { // lwr
            const a=(u[rs]+si)>>>0, al=a&~3, bo=a&3, mv=m.r32(al);
            if(bo===0)u[rt]=(u[rt]&0x00FFFFFF|mv<<24)>>>0;
            else if(bo===1)u[rt]=(u[rt]&0x0000FFFF|mv<<16)>>>0;
            else if(bo===2)u[rt]=(u[rt]&0x000000FF|mv<<8)>>>0;
            else u[rt]=mv;
            break;
          }
          // Stores
          case 40: m.w8((u[rs]+si)>>>0,u[rt]); break; // sb
          case 41: m.w16((u[rs]+si)>>>0,u[rt]); break; // sh
          case 42: { // swl
            const a=(u[rs]+si)>>>0, al=a&~3, bo=a&3, old=m.r32(al), v=u[rt];
            if(bo===0)m.w32(al,v);else if(bo===1)m.w32(al,(old&0xFF000000|v&0x00FFFFFF)>>>0);
            else if(bo===2)m.w32(al,(old&0xFFFF0000|v&0x0000FFFF)>>>0);
            else m.w32(al,(old&0xFFFFFF00|v&0x000000FF)>>>0);
            break;
          }
          case 43: m.w32((u[rs]+si)>>>0,u[rt]); break; // sw
          case 46: { // swr
            const a=(u[rs]+si)>>>0, al=a&~3, bo=a&3, old=m.r32(al), v=u[rt];
            if(bo===0)m.w32(al,(old&0x00FFFFFF|v<<24)>>>0);
            else if(bo===1)m.w32(al,(old&0x0000FFFF|v<<16)>>>0);
            else if(bo===2)m.w32(al,(old&0x000000FF|v<<8)>>>0);
            else m.w32(al,v);
            break;
          }
          case 48: case 49: case 50: case 51: case 52: case 53: case 54: case 55:
          case 56: case 57: case 58: case 59: case 60: case 61: case 62: case 63: break; // FPU
          default: this.err(`op=0x${op.toString(16)} PC=0x${pc.toString(16)}`);
        }
      }
    }
    this.pc = pc; this.npc = npc; this.ic = ic;
  }

  doSyscall(u, m, pc) {
    const num = u[2], a0 = u[4], a1 = u[5], a2 = u[6];
    switch (num) {
      case S_read: {
        const e = this.fds.get(a0);
        if (!e || e.t === 's') { u[2] = e ? 0 : (-1>>>0); return; }
        const tmp = Buffer.alloc(a2);
        const n = fs.readSync(e.h, tmp, 0, a2, e.p);
        m.writeBulk(a1, tmp, n);
        e.p += n;
        u[2] = n;
        return;
      }
      case S_write: {
        const e = this.fds.get(a0);
        if (!e) { u[2] = -1>>>0; return; }
        const tmp = Buffer.alloc(a2);
        m.readBulk(a1, tmp, a2);
        if (e.t === 's') { try { u[2]=fs.writeSync(a0, tmp); } catch(er){u[2]=a2;} return; }
        const n = fs.writeSync(e.h, tmp, 0, a2, e.p);
        e.p += n;
        if (e.p > e.sz) e.sz = e.p;
        u[2] = n;
        return;
      }
      case S_open: {
        const p = m.str(a0), flags = a1, mode = a2;
        let hp = p;
        if (p === 'doom.wad' || p === './doom.wad') hp = '/app/doom.wad';
        try {
          const hf = xlatFlags(flags);
          const h = fs.openSync(hp, hf, mode || 0o644);
          const fd = this.nfd++;
          let sz = 0;
          try { sz = fs.fstatSync(h).size; } catch(er){}
          this.fds.set(fd, {t:'f', h, p:0, sz});
          u[2] = fd;
        } catch(er) { u[2] = -1>>>0; }
        return;
      }
      case S_close: {
        const e = this.fds.get(a0);
        if (!e) { u[2] = -1>>>0; return; }
        if (e.t === 'f') try { fs.closeSync(e.h); } catch(er){}
        this.fds.delete(a0);
        u[2] = 0;
        return;
      }
      case S_lseek: {
        const e = this.fds.get(a0);
        if (!e || e.t !== 'f') { u[2] = -1>>>0; return; }
        const off = (a1<<0)>>0, wh = a2;
        let np;
        if (wh===0) np=off; else if(wh===1) np=e.p+off; else np=e.sz+off;
        if (np<0) { u[2]=-1>>>0; } else { e.p=np; u[2]=np>>>0; }
        return;
      }
      case S_brk: {
        if (a0===0 || a0<=this.heapEnd) u[2]=this.heapEnd;
        else { this.heapEnd=a0; u[2]=a0; }
        return;
      }
      case S_exit: this.exitCode=a0; return;
      case S_fsync: u[2]=0; return;
      case S_rename: { const o=m.str(a0),n=m.str(a1); try{fs.renameSync(o,n);u[2]=0;}catch(e){u[2]=-1>>>0;} return; }
