      default: this.err(`syscall ${num} PC=0x${(pc-4).toString(16)}`);
    }
  }

  err(msg) { console.error('ERR: ' + msg); process.exit(1); }
}

// Main
const elf = loadELF('/app/doomgeneric_mips');
const mem = new Mem();
for (const s of elf.segs) mem.loadSeg(s.va, elf.data, s.off, s.fsz);
const cpu = new CPU(mem, elf.entry);
cpu.u[29] = 0x7FFF0000;
cpu.heapEnd = 0x404b2000;
try { fs.mkdirSync('/tmp', {recursive:true}); } catch(e) {}
console.error('Running...');
const t0 = Date.now();
const exit = cpu.run();
const dt = (Date.now()-t0)/1000;
console.error(`Exit: ${exit}, ${cpu.ic} insns in ${dt.toFixed(1)}s (${Math.floor(cpu.ic/dt)} ips)`);
